const search = $('Authorize and Lexical Search').first().json;
const scope = search.search_scope || 'all';
const vectorResults = $input.all()
  .filter((item) => item.json.document?.pageContent)
  .map((item) => ({
    content: item.json.document.pageContent,
    metadata: item.json.document.metadata || {},
    score: item.json.score
  }))
  .filter((item) => scope !== 'documents' || item.metadata.content_type === 'file');

return [{ json: {
  authorized: search.authorized,
  user_id: search.user_id,
  chat_id: search.chat_id,
  query: search.query,
  search_scope: scope,
  lexical_results: search.lexical_results || [],
  vector_results: vectorResults
} }];

