const source = $('Merge Hybrid Results').first().json;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const response = source.authorized
  ? String($json.text || $json.output || 'У пам’яті нічого не знайдено.').trim()
  : '⛔ Доступ до Inbox Agent не дозволено.';
const plainResponse = response.replace(/\*\*/g, '').replace(/__/g, '').replace(/`/g, '');
return [{ json: { ...source, response: escapeHtml(plainResponse) } }];
